@startuml

abstract class Iterable {
  __iter__
}

abstract class Reversible {
  __reversed__
}

abstract class Sized {
  __len__
}

abstract class Container {
  __contains__
}

abstract class Collection {
  __contains__
  __iter__
  __len__
}

abstract class Sequence {
  __getitem__
  __len__
  __contains__
  __iter__
  __reversed__
  index
  count
}

abstract class MutableSequence {
  __getitem__
  __setitem__
  __delitem__
  __len__
  insert
  __contains__
  __iter__
  __reversed__
  index
  count
  append
  reverse
  extend
  pop
  remove
  __iadd__
}

Reversible --|> Iterable
Collection --|> Iterable
Collection --|> Sized
Collection --|> Container
Sequence --|> Reversible
Sequence --|> Collection
MutableSequence --|> Sequence

@enduml
